final:
module gray_code_counter (
    input clk,
    input rst_n,
    input en,
    output reg [4:0] gray_count
);

reg [4:0] invalid_gray;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        invalid_gray <= 5'b00000;
        gray_count <= 5'b00000;
    end else if (en) begin
        invalid_gray <= invalid_gray + 1;
        gray_count <= invalid_gray ^ (invalid_gray >> 1);
    end
end

endmodule
